import pandas as pd

df1 = pd.DataFrame({
    'id': [1, 2, 3],
    'name': ['Alice', 'Bob', 'Charlie']
})

df2 = pd.DataFrame({
    'id': [1, 2, 3],
    'age': [25, 30, 35]
})

# Merge on 'id' column
merged = pd.merge(df1, df2, on='id')

print(merged)
